            char[] c = Character.toChars(codePoint);
            out.write(c);
        } else {
            // If consumed, move the position by the number of characters processed
            pos += consumed;
        }
        // Move to the next code point
        pos += charCount; // This ensures that we skip the correct number of characters
    }
}
```

